 const joshVsAircotedivoire = "{\"parsed\":{\"_path\":\"/fr/_archived/josh-vs-aircotedivoire\",\"_dir\":\"_archived\",\"_draft\":false,\"_partial\":true,\"_locale\":\"\",\"title\":\"Josh Cahill Meets Air Côte d'Ivoire (And Drama Ensues)\",\"description\":\"Analysis of the controversy between aviation vlogger Josh Cahill and Air Côte d'Ivoire: between a Booking.com ticket, high-altitude recovery, and improvised crisis management.\",\"image\":\"/images/articles/joshcahill.jpg\",\"createdAt\":\"04-11-2025\",\"id\":170,\"keywords\":\"Josh Cahill, Air Côte d'Ivoire, aviation controversy, Booking.com, business class, inaugural flight, aviation influencer, OTA, airline customer service\",\"summary\":\"Vlogger Josh Cahill accuses Air Côte d'Ivoire of fraud after a downgrade. But one detail changes everything: his half-price ticket via Booking.com. Analysis of a controversy where responsibility is shared between omissions and improvised crisis management.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"A word from the author: Before diving in, let me be clear:\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nI have no particular allegiance to Air Côte d'Ivoire.\\nI'm also a big fan of your work, Josh. I've followed your channel for years and genuinely appreciate the transparency and detail you bring to aviation reviews.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"This analysis comes from that place of respect for both parties involved - which is exactly why I think this particular story deserves a closer look at all the pieces.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"josh-cahill-meets-air-côte-divoire-and-drama-ensues\"},\"children\":[{\"type\":\"text\",\"value\":\"Josh Cahill Meets Air Côte d'Ivoire (And Drama Ensues)\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Josh Cahill, renowned aviation vlogger, recently published a video recounting his latest adventures with Air Côte d'Ivoire. This video triggered a major online controversy, sparking passionate reactions from fans and critics alike. It must be said that Josh didn't mince words about his experience with the Ivorian airline.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"its-a-scam\"},\"children\":[{\"type\":\"text\",\"value\":\"It's A SCAM.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Has he declared, following a series of inconveniences encountered before and during his flight. The problems began at check-in, where JC had an unpleasant surprise: having mentally prepared to fly business class, he found himself in economy, without clear explanation from ground staff.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"a-detail-that-changes-the-altitude-of-the-debate\"},\"children\":[{\"type\":\"text\",\"value\":\"A detail that changes the altitude of the debate\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"His business class ticket at €1,000.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"For a Paris-Abidjan business class flight, this is unusually low. Air Côte d'Ivoire's normal fare runs around €2,200-2,300.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Even more revealing: a ground agent explicitly mentioned that this type of problem frequently occurs with reservations made via Booking.com. Yet in his video, JC completely omits mentioning the intermediary. All the blame is directed solely at Air Côte d'Ivoire.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Maybe an oversight, but a significant one.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"For such an experienced traveler - over 800 flights - this omission raises questions. Travel professionals know that bookings via online travel agencies can generate management turbulence that only the intermediary can resolve. The choice not to mention this detail in a public review raises questions about the completeness of the review.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"In laymen's terms: if you book through a third party, any issues often stem from that intermediary, not the airline itself. Omitting this fact skews the narrative and unfairly targets the airline.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"air-côte-divoire-high-altitude-recovery-followed-by-an-improvised-landing\"},\"children\":[{\"type\":\"text\",\"value\":\"Air Côte d'Ivoire: high-altitude recovery... followed by an improvised landing\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Despite the rocky start, Air Côte d'Ivoire managed an impressive recovery mid-flight. The chief ground agent personally intervened, upgrading JC to a better seat and ensuring a quality service for the remainder of the journey. This demonstrated a commendable commitment to customer satisfaction.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"That said, Air Côte d'Ivoire didn't navigate smooth skies either. Their performance proved extremely uneven.\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"what-took-off\"},\"children\":[{\"type\":\"text\",\"value\":\"What took off:\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"A brand new, well-equipped Airbus A330-900 Neo\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"High-altitude recovery with an upgrade initiated by the station manager\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Quality onboard service during the outbound flight\"}]}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"what-crashed\"},\"children\":[{\"type\":\"text\",\"value\":\"What crashed\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"A chaotic check-in process that got the experience off to a bad start\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Less convincing crew service on the return flight\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Post-incident follow-up could be better: no official explanation, no formal apology, no refund of the fare difference .\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"This last point represents a real air pocket in their strategy. Even after upgrading the passenger during the flight, ACI never contacted JC again. For a company seeking to take flight in the long-haul market, this lack of after-sales service is a missed opportunity.\\nMoreover, blocking JC on Instagram - blocking an influencer with nearly a million subscribers - transforms poor management into a delicate situation. This confrontational approach reinforces the impression of a \\\"power struggle\\\" rather than a willingness to dialogue.\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"an-escalation-that-raises-questions\"},\"children\":[{\"type\":\"text\",\"value\":\"An escalation that raises questions\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"In his video, JC uses particularly strong terms like \\\"segregation\\\" and \\\"racist\\\" to describe certain incidents that seem relatively minor: difficulties filming, a wait at boarding. For someone already banned from flying Qatar Airways, one wonders if there isn't a tendency to amplify situations.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Do these serious accusations deserve to be used for these specific incidents? The question remains in holding pattern, but the use of this rhetoric certainly contributes to the intensity of the controversy.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"the-real-flight-lesson\"},\"children\":[{\"type\":\"text\",\"value\":\"The real flight lesson\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ultimately, this affair illustrates how a succession of misunderstandings on both sides can create a media storm where a bit of professionalism and good faith would have allowed a smooth flight.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"This type of incident can happen to any airline, especially during an inaugural flight when teams are still finding their rhythm. What really matters is the ability to learn from these turbulences. Air Côte d'Ivoire has already shown it knows how to react in-flight with its spontaneous upgrade and quality equipment.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"For influencers: transparency is the flight instrument of credibility. Omitting important information, even unintentionally, transforms a legitimate critique into an incomplete narrative. With great reach comes great responsibility - and nearly a million subscribers means your words carry weight that can either build bridges or burn them. A more complete picture, including the Booking.com factor, would have served both your audience and the truth better.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"I'm convinced that with a bit more experience and better after-sales service structure, Air Côte d'Ivoire will navigate more serenely in the competitive long-haul skies. African airlines have every right to their place on the international stage, and this incident is just one flight lesson among others on the path to maturity.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Both parties have room to grow: one in operational excellence and customer care, the other in journalistic completeness. That's not criticism - that's an opportunity for everyone to fly higher next time.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"a-closing-note\"},\"children\":[{\"type\":\"text\",\"value\":\"A closing note\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"As a final word, Josh, you'd better get used to seeing terms like \\\"maudia\\\" (cursed), \\\"ton b####\\\" (and other colorful expressions) flourishing in your comments section. West African internet culture has its own unique flavor when it comes to expressing displeasure, and you are about to get a good taste of it.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"And if you speak a wee bit of French, I'd recommend reading this piece on crisis management: \"},{\"type\":\"element\",\"tag\":\"a\",\"props\":{\"href\":\"https://jeanluchouedanou.blogspot.com/2024/03/la-regle-des-72-heures-ou-comment-gerer.html\",\"rel\":[\"nofollow\"]},\"children\":[{\"type\":\"text\",\"value\":\"https://jeanluchouedanou.blogspot.com/2024/03/la-regle-des-72-heures-ou-comment-gerer.html\"}]},{\"type\":\"text\",\"value\":\" - it might offer some perspective on how things could have been handled differently on both sides.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Safe travels, and here's hoping your next African adventure goes more smoothly. ✈️\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"josh-cahill-meets-air-côte-divoire-and-drama-ensues\",\"depth\":2,\"text\":\"Josh Cahill Meets Air Côte d'Ivoire (And Drama Ensues)\"},{\"id\":\"its-a-scam\",\"depth\":2,\"text\":\"It's A SCAM.\"},{\"id\":\"a-detail-that-changes-the-altitude-of-the-debate\",\"depth\":2,\"text\":\"A detail that changes the altitude of the debate\"},{\"id\":\"air-côte-divoire-high-altitude-recovery-followed-by-an-improvised-landing\",\"depth\":2,\"text\":\"Air Côte d'Ivoire: high-altitude recovery... followed by an improvised landing\",\"children\":[{\"id\":\"what-took-off\",\"depth\":3,\"text\":\"What took off:\"},{\"id\":\"what-crashed\",\"depth\":3,\"text\":\"What crashed\"},{\"id\":\"an-escalation-that-raises-questions\",\"depth\":3,\"text\":\"An escalation that raises questions\"}]},{\"id\":\"the-real-flight-lesson\",\"depth\":2,\"text\":\"The real flight lesson\"},{\"id\":\"a-closing-note\",\"depth\":2,\"text\":\"A closing note\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:_archived:josh-vs-aircotedivoire.md\",\"_source\":\"content\",\"_file\":\"fr/_archived/josh-vs-aircotedivoire.md\",\"_stem\":\"fr/_archived/josh-vs-aircotedivoire\",\"_extension\":\"md\"},\"hash\":\"Tgg4CM1uAT\"}";

export { joshVsAircotedivoire as default };
